SELECT nurse_name
FROM nurses
WHERE nurse_specialty = 'ICU';

SELECT DISTINCT portal_id
FROM patients
WHERE admission_date >= '2023-01-10' AND discharge_date <= '2023-01-20';

SELECT DISTINCT patient_id
FROM patients
ORDER BY patient_id;

SELECT COUNT(DISTINCT patient_id) AS total_patients
FROM icu_records
WHERE diagnosis_id = (SELECT diagnosis_id FROM diagnoses WHERE diagnosis_name = 'AMS');

SELECT COUNT(patient_id) AS total_patients
FROM room_assignments
WHERE room_id = 0;

SELECT COUNT(DISTINCT patient_id) AS patient_count
FROM icu_records
WHERE diagnosis_id = (SELECT diagnosis_id FROM diagnoses WHERE diagnosis_name = 'AMS');

SELECT COUNT(*) AS blue_cross_patients
  FROM insurance
  WHERE provider = 'Blue Cross';
